struct Position: Identifiable, Codable {
    let id = UUID()
    let symbol: String
    var quantity: Int
    var averageCost: Double
    var marketPrice: Double

    var marketValue: Double {
        Double(quantity) * marketPrice
    }
}

struct Portfolio: Codable {
    var cash: Double
    var positions: [Position]

    var totalValue: Double {
        cash + positions.reduce(0) { $0 + $1.marketValue }
    }

    static let mock = Portfolio(
        cash: 25000,
        positions: [
            Position(symbol: "AAPL", quantity: 50, averageCost: 172.40, marketPrice: 176.20),
            Position(symbol: "MSFT", quantity: 20, averageCost: 402.10, marketPrice: 408.55),
            Position(symbol: "NVDA", quantity: 15, averageCost: 845.00, marketPrice: 862.30)
