final class MarketDataService: ObservableObject {
    @Published var quotes: [String: Quote] = [:]
    private var timer: Timer?

    func startStreaming(symbols: [String]) {
        stopStreaming()
        seed(symbols: symbols)
        timer = Timer.scheduledTimer(withTimeInterval: 1.2, repeats: true) { [weak self] _ in
            self?.update(symbols: symbols)
        }
    }

    func stopStreaming() {
        timer?.invalidate()
        timer = nil
    }

    private func seed(symbols: [String]) {
        let base: [String: Double] = [
            "AAPL": 176.20,
            "MSFT": 408.55,
            "TSLA": 182.10,
            "NVDA": 862.30,
            "AMZN": 178.45
        ]
        var seeded: [String: Quote] = [:]
        for symbol in symbols {
            let price = base[symbol] ?? Double.random(in: 50...500)
            seeded[symbol] = Quote(symbol: symbol, price: price, change: 0, changePercent: 0, timestamp: Date())
        }
        quotes = seeded
    }

    private func update(symbols: [String]) {
        var updated = quotes
        for symbol in symbols {
            let current = updated[symbol]?.price ?? Double.random(in: 50...500)
            let delta = Double.random(in: -1.8...1.8)
            let newPrice = max(1, current + delta)
            let change = delta
            let changePercent = current == 0 ? 0 : delta / current
            updated[symbol] = Quote(symbol: symbol, price: newPrice, change: change, changePercent: changePercent, timestamp: Date())
        }
        DispatchQueue.main.async {
            self.quotes = updated
        }
    }
}

final class PortfolioService: ObservableObject {
    @Published var portfolio: Portfolio = .mock

    func loadPortfolio() {
        portfolio = .mock
    }

    func apply(order: TradeOrder) -> Bool {
        var portfolio = self.portfolio
        let cost = Double(order.quantity) * order.price

        switch order.side {
        case .buy:
            guard portfolio.cash >= cost else { return false }
            portfolio.cash -= cost
            if let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                let existing = portfolio.positions[index]
                let totalShares = existing.quantity + order.quantity
                let totalCost = (Double(existing.quantity) * existing.averageCost) + cost
                portfolio.positions[index].quantity = totalShares
                portfolio.positions[index].averageCost = totalCost / Double(totalShares)
                portfolio.positions[index].marketPrice = order.price
            } else {
                portfolio.positions.append(Position(symbol: order.symbol, quantity: order.quantity, averageCost: order.price, marketPrice: order.price))
            }
        case .sell:
            guard let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) else { return false }
            guard portfolio.positions[index].quantity >= order.quantity else { return false }
            portfolio.positions[index].quantity -= order.quantity
            portfolio.positions[index].marketPrice = order.price
            portfolio.cash += cost
            if portfolio.positions[index].quantity == 0 {
                portfolio.positions.remove(at: index)
            }
        }

        DispatchQueue.main.async {
            self.portfolio = portfolio
        }
        return true
    }
}

final class TradingService: ObservableObject {
    @Published var orders: [TradeOrder] = []
    @Published var alerts: [AppAlert] = []

    func loadOrders() {
        orders = []
    }

    func execute(order: TradeOrder, portfolioService: PortfolioService) {
        var mutableOrder = order
        DispatchQueue.main.async {
            self.orders.insert(mutableOrder, at: 0)
        }

        DispatchQueue.global().asyncAfter(deadline: .now() + 0.8) {
            let success = portfolioService.apply(order: mutableOrder)
            mutableOrder.status = success ? .filled : .rejected

            DispatchQueue.main.async {
                if let index = self.orders.firstIndex(where: { $0.id == mutableOrder.id }) {
                    self.orders[index] = mutableOrder
                }
                self.alerts.append(
                    AppAlert(
                        type: success ? .success : .error,
                        message: success
                        ? "Order filled: \(mutableOrder.side.rawValue.capitalized) \(mutableOrder.quantity) \(mutableOrder.symbol) at \(mutableOrder.price.currency)"
                        : "Order rejected: insufficient funds or shares"
                    )
                )
                self.trimAlerts()
            }
        }
    }

    private func trimAlerts() {
        if alerts.count > 3 {
            alerts.removeFirst(alerts.count - 3)
        }
    }
}

final class APIClient {
    private let baseURL = URL(string: "https://api.investment-platform.example")!

    func authenticate(apiKey: String, apiSecret: String) -> String {
        let payload = "\(apiKey):\(apiSecret):\(Date().timeIntervalSince1970)"
        let signature = HMACSigner.sign(payload: payload, secret: apiSecret)
        let token = Data("\(apiKey).\(signature)".utf8).base64EncodedString()
        _ = buildRequest(path: "/auth/login", method: "POST", token: nil, body: ["apiKey": apiKey, "signature": signature])
        return token
    }

    func buildRequest(path: String, method: String, token: String?, body: [String: Any]?) -> URLRequest {
        var request = URLRequest(url: baseURL.appendingPathComponent(path))
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("iOS", forHTTPHeaderField: "X-Client-Platform")
        if let token {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let body {
            request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        }
        return request
    }
}

enum HMACSigner {
    static func sign(payload: String, secret: String) -> String {
        let key = SymmetricKey(data: Data(secret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        return Data(signature).map { String(format: "%02hhx", $0) }.joined()
    }
}

final class SecureStore {
    func save(value: String, for key: String) {
        let data = Data(value.utf8)
        delete(for: key)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        SecItemAdd(query as CFDictionary, nil)
    }

    func read(for key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess,
              let data = item as? Data,
              let value = String(data: data, encoding: .utf8) else {
            return nil
        }
        return value
    }

    func delete(for key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

extension Double {
    var currency: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: NSNumber(value: self)) ?? "$0.00"
    }

    var formattedPercent: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .percent
        formatter.maximumFractionDigits = 2
        formatter.minimumFractionDigits = 2
        return formatter.string(from: NSNumber(value: self)) ?? "0.00%"
    }
}